// Extrae entity + records del body
const body = $input.first().json.body || $input.first().json;
const entity = String(body.entity || '').toLowerCase().trim();
const records = Array.isArray(body.records) ? body.records : [];

if (records.length === 0) {
  throw new Error('No se recibieron registros para importar');
}

// Agrega metadatos de tracking a cada registro
return records.map((record, index) => ({
  json: {
    ...record,
    _index: index + 1,
    _entity: entity,
    _status: 'pending',
    _error: null,
  }
}));

// Combina el id encontrado (SELECT result) con los datos originales del loop
const found = $input.first().json;
const original = $('Loop por Registro').item.json;

return [{
  json: {
    _found_id:         found.id,
    _index:            original._index,
    _entity:           original._entity,
    _name:             original.name || '',
    name:              original.name              ?? '',
    email:             original.email             ?? '',
    phone_number:      original.phone_number      ?? '',
    identity_document: original.identity_document ?? '',
    internal_id:       original.internal_id       ?? '',
    birthday:          original.birthday          ?? '',
    address:           original.address           ?? '',
    alternative_phone: original.alternative_phone ?? '',
    notes:             original.notes             ?? '',
    rut:               original.rut               ?? '',
    bank_account:      original.bank_account      ?? '',
    is_active:         original.is_active !== undefined ? String(original.is_active) : '',
  }
}];

const prep   = $('Preparar Actualización').item.json;
const result = $input.first().json;

if (result.error || !result.id) {
  const msg = result.error?.message || String(result.error) || 'Error al actualizar registro';
  return [{ json: { _index: prep._index, _entity: prep._entity, _status: 'error', _error: msg, _name: prep._name } }];
}

return [{ json: { _index: prep._index, _entity: prep._entity, _status: 'updated', _id: result.id, _name: prep._name } }];

// Recupera los datos originales del loop para preparar el INSERT
const original = $('Loop por Registro').item.json;

return [{
  json: {
    _index:            original._index,
    _entity:           original._entity,
    _name:             original.name || '',
    name:              original.name              ?? '',
    email:             original.email             ?? '',
    phone_number:      original.phone_number      ?? '',
    identity_document: original.identity_document ?? '',
    internal_id:       original.internal_id       ?? '',
    birthday:          original.birthday          ?? '',
    address:           original.address           ?? '',
    alternative_phone: original.alternative_phone ?? '',
    notes:             original.notes             ?? '',
    rut:               original.rut               ?? '',
    bank_account:      original.bank_account      ?? '',
    is_active:         original.is_active !== undefined ? String(original.is_active) : '',
  }
}];

const prep   = $('Preparar Inserción').item.json;
const result = $input.first().json;

if (result.error || !result.id) {
  const msg = result.error?.message || String(result.error) || 'Error al insertar registro';
  return [{ json: { _index: prep._index, _entity: prep._entity, _status: 'error', _error: msg, _name: prep._name } }];
}

return [{ json: { _index: prep._index, _entity: prep._entity, _status: 'inserted', _id: result.id, _name: prep._name } }];

const item = $input.first().json;
return [{ json: {
  _index:  item._index,
  _entity: item._entity,
  _status: 'skipped',
  _error:  `Entidad '${item._entity}' no soportada en esta versión`,
  _name:   item.name || ''
} }];

// Recibe todos los items procesados del loop y genera el resumen
const items = $input.all();

const inserted = items.filter(i => i.json._status === 'inserted').length;
const updated  = items.filter(i => i.json._status === 'updated').length;
const skipped  = items.filter(i => i.json._status === 'skipped').length;
const errors   = items.filter(i => i.json._status === 'error').length;
const total    = items.length;

const error_details = items
  .filter(i => i.json._status === 'error')
  .map(i => ({
    row:   i.json._index,
    name:  i.json._name  || '',
    error: i.json._error || 'Error desconocido',
  }));

return [{ json: { total, inserted, updated, skipped, errors, error_details } }];
